var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"오… 오오…!","JPN":"お……おお……！","ENG":"W-whoa...!","TWN":"喔…喔喔…！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"지원군이다! 구원 기사단이 우릴 도우러 왔어!","JPN":"援軍だ！　救世騎士団が俺たちを助けに来たんだ！","ENG":"Backup! The Knights of Redemption are here to help us!","TWN":"是援軍！救贖騎士團來救我們了！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"대장님! 마을을 막고 있던 괴수들이 물러나고 있습니다!","JPN":"隊長！　村を塞いでいた怪獣たちが退いていきます！","ENG":"Captain! The monsters that were obstructing the village are moving back!","TWN":"隊長! 圍堵村莊的怪獸開始撤退了！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_NULL","text":{"KOREA":"지금이 기회입니다. 당장 따라가 놈들의 뒤를 쳐야 합니다!","JPN":"今がチャンスです。今すぐ追いかけて奴らを討ちましょう！","ENG":"Now is our chance. We need to follow them and strike while they're distracted!","TWN":"趁現在！立刻追上去迎擊！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"진정하고 잘 보도록. 일정한 간격을 둔 사방진으로부터 공격이 뻗어 나오고 있다.","JPN":"落ち着いてよく見ろ。一定の距離を置いて四方から攻撃をしかけている。","ENG":"Calm down and observe. They are attacking from four different directions.","TWN":"冷靜地看清楚，各自間隔一段距離散落在四個方位進行攻擊。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"선발대 구출만이 목적이었다면 저런 식으로 화력을 분산시킬 필요는 없어.","JPN":"先発隊の救出だけが目的なら、あんな風に火力を分散させる必要はない。","ENG":"They wouldn't split up their forces if rescuing the advance party was their only objective.","TWN":"若目的只是要救出先遣隊，沒必要這樣分散火力。"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"각각의 진으로 병사들을 나눠라! 구원기사단과 합류해, 이곳에서 놈들을 쓰러트린다!","JPN":"各々の陣に兵士を分けろ！　救世騎士団と合流し、ここで奴らを倒す！","ENG":"Split into four groups and head to the four different points! We will join the Knights of Redemption and vanquish the monsters here!","TWN":"把兵力分散到四個方位！與救援騎士團會合，在這裡消滅怪獸！"},"stage":{"bg":"CAMP","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하의 작전대로 흘러가는군요. 제국군의 병력이 넷으로 나뉘었습니다.","JPN":"殿下の作戦どおりですね。帝国軍の兵力が四つに分かれました。","ENG":"It is going according to your plan, Your Highness. The imperial soldiers are divided into four.","TWN":"按照殿下的作戰計劃進行中呢。帝國軍的兵力已分散至四方。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아무렴. 인류 최후의 군세가 이 정도도 해주지 않으면 곤란하지.","JPN":"当たり前だ。人類最後の軍勢がこの程度もできないようでは困る。","ENG":"Of course. I'd expect nothing less from the last army of humanity.","TWN":"當然。如果人類最後的軍隊連這點事都辦不到還能做什麼。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"대열이 갖춰지기 전까지 빠져나오는 놈들은 샬롯과 평민이 맡도록.","JPN":"隊列が整うまで、抜け出てくる怪獣はシャーロットと平民が処理しろ。","ENG":"Carlota and peasant, you two are to handle the ones that escape before the line is formed.","TWN":"在隊伍成形前，夏洛特和平民就負責那些試圖逃跑的怪獸。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"작전대로 놈들을 에워싼 뒤, 포위망을 좁혀 단숨에 요격한다!","JPN":"作戦どおりに奴らを囲み、包囲網を狭め一気に迎え撃つ！","ENG":"We shall stay on course! Surround them, move in, and make a swift strike!","TWN":"按照計劃包圍怪獸後，再縮小包圍範圍，一舉殲滅怪獸！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"네!","JPN":"はい！","ENG":"Yes, Your Highness!","TWN":"是！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하. 제게만 별다른 지시가 없으십니다만.","JPN":"殿下。私にだけ特にご指示がありませんが。","ENG":"Your Highness, I seem to be the only one without any orders.","TWN":"殿下，好像只有我沒收到任何指示？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하. 고귀하신 성녀께 궂은 일을 시킬 수야 있나.","JPN":"ハハ。貴い聖女に汚れ仕事をさせるわけにはいくまい。","ENG":"Ha ha. How ever could I make our virtuous Saintess work?","TWN":"哈哈，怎麼能讓高貴的聖女去做這些粗活呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"등산하느라 꽤 피곤해 보이는데, 평소처럼 가만히 서서 병사들 사기나 올리도록.","JPN":"山登りでかなり消耗したと見える。いつものようにじっと立って、兵士の士気でも上げていることだな。","ENG":"You look quite tired after the hike, so why don't you raise the morale of soldiers while standing still like you always do?","TWN":"你應該爬山爬得很累吧？就像平時一樣站著鼓舞士氣就好。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그게 싫으면 끝난 뒤에 평민에게 떨 아양이나 생각해 놓던가 말이다.","JPN":"それが嫌なら、終わった後に平民にどうやって尻尾を振るか考えておくのはどうだ？","ENG":"Or you could come up with ways to court the peasant after the fight.","TWN":"不喜歡的話，就想想結束後怎麼討好平民吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"전하?","JPN":"殿下？","ENG":"Your Highness?","TWN":"殿下？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이……!","JPN":"この……！","ENG":"That...!","TWN":"你這個……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"이 능구렁이 같은 황태자 자식이 진짜!","JPN":"この狸皇太子が！","ENG":"That sly, condescending crown prince bastard!","TWN":"狡猾的皇太子！可惡！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MOVEMENT_12"},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"와아아아아아!!","JPN":"ワアアアアア！！","ENG":"Woooooh!!","TWN":"哇喔喔喔喔～～！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHEER"},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"괴수들을 해치웠다! 우리가 이긴 거야!","JPN":"怪獣どもをやっつけたぞ！　俺たちが勝ったんだ！","ENG":"We defeated the monsters! We won!","TWN":"我們打敗怪獸了！我們贏了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"구원자님께서 이곳까지 와 주셨으니, 우리에게 더 이상 패배란 없다!","JPN":"救世主様がいらしたんだ、もう俺たちに負けなどない！","ENG":"The Savior came all the way here for us! We're never going to lose again!","TWN":"現在救贖者大人大人來到在這裡，我們就不會再輸了！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"황태자 전하 만세! 구원자님 만세! 아르카데나 제국 만세!","JPN":"皇太子殿下万歳！　救世主様万歳！　アルカデナ帝国万歳！","ENG":"Long live His Highness! Long live the Savior! Long live Arcadena!","TWN":"皇太子 殿下！救贖者大人大人萬歲！艾爾卡特納帝國萬歲！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"일이 이렇게 되다니. 정말 드릴 말씀이 없습니다.","JPN":"このようなことになり、誠に面目ございません。","ENG":"I am ashamed to be greeting you in these circumstances.","TWN":"事情變成如此，我實在是沒臉見殿下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"설마 전하께서 직접 와 주실 줄은…","JPN":"まさか、殿下直々にお越しくださるとは……","ENG":"I didn't think you would travel all the way here yourself...","TWN":"竟然讓殿下親自前來…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"괜찮다. 힘든 여건에서 잘 버텨 주었군.","JPN":"問題ない。厳しい条件下でよく耐えた。","ENG":"You are excused. You've managed to stand firm in this dire situation.","TWN":"沒事，在這麼艱難的情況下，多虧你們能撐得下去。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"적이 수만 많은 조무래기들이라 생각했는데, 꼭 그렇지만은 않았던 모양이야.","JPN":"敵は数だけの雑魚だと思っていたが、そうでもなかったようだ。","ENG":"We thought the enemy only had an advantage in numbers, but I see that wasn't the case.","TWN":"本來以為敵人只是一些小嘍囉，但看來並非如此。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"괴수들이 마을을 습격하지 않아 예정에 없던 소모전이 이어졌습니다.","JPN":"怪獣どもが村を襲撃しなかったため、予定にはなかった消耗戦が続きました。","ENG":"The monsters didn't attack the village, and it became an expected war of attrition.","TWN":"怪獸沒有襲擊村莊，沒想到接下來卻是場消耗戰。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"괴수의 수는 늘어나는 반면, 병사들은 피로에 지쳐가는 탓에…","JPN":"怪獣の数が多くなるにつれ、兵士は疲労で動けなくなり……","ENG":"The monsters grew in number, but the soldiers gradually became tired...","TWN":"怪獸的數量不斷增加，導致士兵們的身體越來越疲於應戰…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"지나간 일을 신경 쓸 필요는 없지. 남은 건 우리에게 맡기고 푹 쉬도록.","JPN":"終わったことを気にする必要はない。後処理は我らに任せ、ゆっくりと休め。","ENG":"No need to concern ourselves with past matters. Leave the rest to us and get some shut-eye.","TWN":"過去的事無需再提，剩下的就交給我們，你們好好休息吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그런데… 이 자는?","JPN":"ところで……この者は？","ENG":"So... Who might this be?","TWN":"不過…這個人是？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"처음 뵙겠습니다, 전하.","JPN":"お初にお目にかかります、殿下。","ENG":"Pleased to make your acquaintance, Your Highness.","TWN":"初次見面，殿下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"마을의 촌장으로서 전하를 늦게 모시는 이 늙은이의 우둔함을 용서해주시길.","JPN":"村長として、遅ればせながら殿下にご挨拶を申し上げるご無礼を、どうかお許しくださいませ。","ENG":"Forgive me for not having greeted you earlier.","TWN":"我身為村長，這麼晚才來迎接殿下，還請殿下恕罪。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"네 이놈! 감히 누구 앞인 줄 알고 그리 떳떳하게 고개를 드느냐!","JPN":"貴様！　殿下のお前で頭が高いぞ！","ENG":"Do you realize who you're speaking to?! You are to bow in the presence of His Highness!","TWN":"大膽刁民！在皇太子面前還不快跪下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"놔둬라. 이런 곳에서까지 황족의 권위를 내세우면 되겠나.","JPN":"やめておけ。このようなところでまで皇族の権威を打ち立てる必要はなかろう。","ENG":"It is fine. I cannot be enforcing royalty in a place like this.","TWN":"沒事，在這種地方還要耍官威嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그나저나 꽤 북적거리는군. 마을 주민의 대부분은 피난을 갔다 들었다만?","JPN":"それより、ずいぶんと賑わっているな。村の住民は、ほとんどが避難していると聞いたが。","ENG":"Anyway, the place seems to be pretty crowded. I heard most of the villagers evacuated, though.","TWN":"不過，沒想到這裡的居民蠻多的，大家都已經撤離嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"떠날 사람은 진즉 떠난 뒤입니다. 남은 사람은 노예 출신이거나 갈 곳 없는 토착민들이지요.","JPN":"去るべき者は、すでにこの村から出ております。残ったのは奴隷出身か、他に行くあてのない土着民です。","ENG":"Everyone who could leave already left. The ones remaining are former slaves or natives.","TWN":"該撤的目前都已撤離，剩下都是奴隸或無處可去的主著。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"노예, 말인가요?","JPN":"奴隷、ですか？","ENG":"Slaves?","TWN":"奴隸嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"몬테는 세상과 단절된 위치에 있으니 말입니다.","JPN":"モンテは世間と隔絶された位置にありますから。","ENG":"Monte is detached from the rest of the world.","TWN":"蒙特村與世隔絕，"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"사회에서 벗어나 새로운 삶을 시작하려는 이들이 종종 이곳을 찾아오지요.","JPN":"社会から外れ、新しい人生を始めようとする者が時々ここへやってくるのです。","ENG":"So it is sometimes sought by those who wish to escape society and start a new life.","TWN":"所以經常有離開社會尋找新生活的人來這裡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"설마 구원 기사단분들이 찾아오실 줄은 몰랐지만 말입니다. 허허.","JPN":"まさか、救世騎士団の方々までいらっしゃるとは思いませんでしたがのう。ほっほ。","ENG":"However, I did not expect the Knights of Redemption to pay a visit. Ha ha.","TWN":"只是沒想到救贖騎士團會來這裡。呵呵。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"늦어서 죄송합니다. 조금만 빨리 왔다면 더 많은 분들을 살릴 수 있었을 텐데……","JPN":"遅れてすみません。もう少し早く来られたら、もっと多くの人々を助けることができたはずなのに……","ENG":"I'm sorry we're late. If we had arrived sooner, we might have saved a lot more people...","TWN":"很抱歉來得太遲。如果能早一點來，就能救更多的人……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L34_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"200년 만에 제복을 물려받으셨다더니, 구원자님께서는 심성도 참 고우십니다.","JPN":"200年ぶりに礼装を受け継いだと聞きましたが、救世主様はお優しい。","ENG":"I heard you inherited that uniform after 200 years. You have such a kind heart, Savior.","TWN":"二百年來首次穿上這身制服，救贖者大人大人果然心地善良。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"삶이란 연속된 우연으로 가장된 필연과도 같은 것이지요.","JPN":"人生とは、連続した偶然を装った必然も同じ。","ENG":"Life is like fate disguised as continuous coincidences.","TWN":"生命就像是一系列包裝成偶爾的必然。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"마을 사람들이 떠난 것도, 여러분들이 이곳에 온 것 또한 운명이라면…","JPN":"村の者が去っていったのも、皆さんがここへいらしたのも運命であるならば……","ENG":"If the villagers were destined to leave, and if you were destined to come here...","TWN":"村民離開後，換你們來到這裡，若這是命運…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"적어도 이 짧은 인연에 추억 하나 남겨 보심이 어떠십니까?","JPN":"このささやかな縁に思い出を一つ残してみるのはいかがかな。","ENG":"How would you like to make use of this short moment to make some memories?","TWN":"至少在這短暫的相遇中留下些許回憶如何？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"추억 말인가요?","JPN":"思い出ですか？","ENG":"A memory?","TWN":"回憶？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"왕도에서 열리는 무도회 시기에 맞춰 몬테 또한 대대로 작은 축제를 열었습니다.","JPN":"王都で開かれる舞踏会の時期に合わせて、モンテでも代々小さな祭りを開いてまいりました。","ENG":"For generations, Monte would hold a small festival right around the time that the capital hosted the ball.","TWN":"一直以來，在皇宮舉辦舞會的期間，蒙特也會舉辦小型慶典。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"병사분들이 치료를 받는 동안, 여러분께서는 주민들과 함께 축제를 즐기심이 어떠십니까?","JPN":"どうでしょう。兵士の方々が治療を受けられている間、皆さんは住民と一緒に祭りを楽しまれては。","ENG":"How about you enjoy the festival with the villagers while the soldiers are treated?","TWN":"在士兵們接受治療的期間，各位可以和村民們一起享受慶典。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흠….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯. 병사들이 채비를 갖출 때까지 시간이 얼마나 필요하지?","JPN":"シャーロット。兵士の立て直しに、どのくらいの時間がかかる？","ENG":"Carlota. How long until the soldiers are prepared to march out?","TWN":"夏洛特，士兵們重新整頓好需要多長時間？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L44_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"갑주의 정비나 부상을 고려했을 때 넉넉잡아 3일이 필요합니다, 전하.","JPN":"鎧の整備や兵士の負傷を考えると、多めに見積もって3日は必要かと。","ENG":"Considering the repair of armor and the injured, we would need about three days, Your Highness.","TWN":"考慮到要修理裝備和處理傷口，至少需要三天，殿下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L46_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"부상자들을 내버려둘 수도 없으니 별다른 선택지는 없겠군.","JPN":"怪我人を放っておくわけにはいかない。他に選択肢はないな。","ENG":"Looks like there is no other choice since we cannot leave the injured untended.","TWN":"不能就這麼放著傷者不管，看來也沒其他的選擇。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"좋다. 그대의 호의는 기쁘게 받아들이도록 하지.","JPN":"いいだろう。喜んでそなたの言葉に甘えることにしよう。","ENG":"Very well. We shall gladly accept your offer.","TWN":"那好吧，我就愉快地接受村長的好意。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"제국을 수호하는 기사단이 놀음에 빠져 있을 수는 없다고 하시지 않았습니까?","JPN":"帝国を守護する騎士団が遊興にふっけているわけにはいかないとおっしゃっていませんでしたか？","ENG":"Were you not the one who said that the knights are supposed to protect the Empire, not dance and carouse the night away?","TWN":"保護帝國的騎士團怎麼能沉迷於享樂呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L1_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하. 목적 없는 놀음과 호의의 수용이 어찌 같을 수 있겠나.","JPN":"ハハ。目的のない遊びと、好意の受容は同じなものか。","ENG":"Ha ha. Meaningless revels and accepting an offer are two different things.","TWN":"哈哈，盲目的享樂和接受好意怎麼混為一談呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"방탕한 축제가 싫으시다면야 먼저 내려가도 말리지는 않으마.","JPN":"ふらちな祭りがお気に召さぬのなら、先に帰ってもいいぞ。","ENG":"I will not stop you if you wish to depart before the debauched revelry.","TWN":"若聖女不喜歡放縱的慶典，你要先下山我也沒意見。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…딱히 싫다고는 안 했습니다.","JPN":"……別に、嫌だとは言っていません。","ENG":"...I didn't say I wanted to leave.","TWN":"…我又沒說不喜歡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"결정이군요. 사람들에게 일러 여러분이 머물 숙소를 마련하겠습니다.","JPN":"決まりですな。村の者たちに話して皆さんがお泊りになる宿をご用意しましょう。","ENG":"Then it's decided. I will notify the others so you will have somewhere to sleep.","TWN":"那就這麼決定，我會請人為各位準備住處。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"별거 없는 마을이지만, 부디 편히 쉬다 가시길.","JPN":"つまらない村ですが、どうかごゆっくりとお休みください。","ENG":"The village doesn't have much to offer, but I hope you have a comfortable stay here.","TWN":"這裡雖然只是個小村莊，但希望你們能好好休息。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};